		executor := agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
			attempts := make([]policyescalation.PowerAttemptRecord, 0, 3)
			recordAttempt := func(report agent.ExecuteBeadReport) {

package server

import (
	"encoding/json"
	"os"
	"path/filepath"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
)

// reportedWorkersAdapter adapts the in-memory worker_ingest registry to the
// ddxgraphql.ReportedWorkersProvider interface used by the reportedWorkers
// query. It also synthesizes in-flight attempts from run-state.json as
// active workers. now is overridable so tests can advance the freshness
// clock without mutating registry timestamps.
type reportedWorkersAdapter struct {
	reg        *workerIngestRegistry
	workingDir string
	mu         sync.RWMutex
	now        func() time.Time
}

func newReportedWorkersAdapter(reg *workerIngestRegistry) *reportedWorkersAdapter {
	return &reportedWorkersAdapter{reg: reg, now: func() time.Time { return time.Now().UTC() }}
}

func newReportedWorkersAdapterWithWorkingDir(reg *workerIngestRegistry, workingDir string) *reportedWorkersAdapter {
	return &reportedWorkersAdapter{
		reg:        reg,
		workingDir: workingDir,
		now:        func() time.Time { return time.Now().UTC() },
	}
}

func (a *reportedWorkersAdapter) currentNow() time.Time {
	a.mu.RLock()
	defer a.mu.RUnlock()
	return a.now()
}

// GetReportedWorkers implements ddxgraphql.ReportedWorkersProvider.
// Returns workers from the ingest registry plus synthesized active workers
// from live run-state.json files. The reportedWorkers query shows both
// registered worker reports (from the worker-server HTTP interface, ADR-022)
// and in-flight attempts (from run-state.json for inline work).
func (a *reportedWorkersAdapter) GetReportedWorkers() []*ddxgraphql.ReportedWorker {
	if a.reg == nil {
		return nil
	}
	now := a.currentNow()
	snap := a.reg.snapshot()
	out := make([]*ddxgraphql.ReportedWorker, 0, len(snap))
	for _, rec := range snap {
		w := &ddxgraphql.ReportedWorker{
			ID:                  rec.WorkerID,
			Project:             rec.Identity.ProjectRoot,
			Harness:             rec.Identity.Harness,
			State:               freshnessState(rec, now),
			LastEventAt:         rec.LastEventAt.UTC().Format(time.RFC3339Nano),
			MirrorFailuresCount: rec.MirrorFailuresCount,
			HadDroppedBackfill:  rec.HadDroppedBackfill,
		}
		if rec.CurrentBead != "" {
			cb := rec.CurrentBead
			w.CurrentBead = &cb
		}
		if rec.CurrentAttempt != "" {
			ca := rec.CurrentAttempt
			w.CurrentAttempt = &ca
		}
		out = append(out, w)
	}

	// Synthesize active workers from live run-state.json for inline work.
	if a.workingDir != "" {
		inFlightWorkers := a.getInFlightWorkers(now)
		out = append(out, inFlightWorkers...)
	}

	return out
}

// getInFlightWorkers returns synthesized ReportedWorker entries for each
// live attempt in run-state.json that has not yet expired.
func (a *reportedWorkersAdapter) getInFlightWorkers(now time.Time) []*ddxgraphql.ReportedWorker {
	runStateDir := ddxroot.JoinProject(a.workingDir, agent.RunStateDirName)
	entries, err := os.ReadDir(runStateDir)
	if err != nil {
		return nil
	}

	var out []*ddxgraphql.ReportedWorker
	for _, entry := range entries {
		if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
			continue
		}
		data, err := os.ReadFile(filepath.Join(runStateDir, entry.Name()))
		if err != nil {
			continue
		}
		var state agent.RunState
		if err := json.Unmarshal(data, &state); err != nil {
			continue
		}
		// Skip expired runs.
		if !state.ExpiresAt.IsZero() && now.After(state.ExpiresAt) {
			continue
		}
		// Synthesize a ReportedWorker from the run-state.
		w := &ddxgraphql.ReportedWorker{
			ID:          "inline-" + state.AttemptID,
			Project:     a.workingDir,
			Harness:     state.Harness,
			State:       "connected",
			LastEventAt: state.RefreshedAt.UTC().Format(time.RFC3339Nano),
		}
		if state.BeadID != "" {
			b := state.BeadID
			w.CurrentBead = &b
		}
		if state.AttemptID != "" {
			att := state.AttemptID
			w.CurrentAttempt = &att
		}
		out = append(out, w)
	}
	return out
}

package activework

import (
	"context"
	"sort"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

// Record describes one fresh source of active work for a bead.
//
// The snapshot reconciles claim-heartbeat leases, worker liveness sidecars,
// and fresh run-state records into one project-scoped view so operator-facing
// status surfaces can agree on what is actively running.
type Record struct {
	WorkerID       string    `json:"worker_id,omitempty"`
	BeadID         string    `json:"bead_id,omitempty"`
	AttemptID      string    `json:"attempt_id,omitempty"`
	Owner          string    `json:"owner,omitempty"`
	Phase          string    `json:"phase,omitempty"`
	Source         string    `json:"source,omitempty"`
	LastActivityAt time.Time `json:"last_activity_at"`
}

// Snapshot is the shared active-work summary used by bead, work, and GraphQL
// status views.
type Snapshot struct {
	Count   int      `json:"count"`
	BeadIDs []string `json:"bead_ids"`
	Records []Record `json:"records"`
}

// Collect returns a fresh active-work snapshot for projectRoot.
//
// A record is considered active when it is fresh under the source-specific
// freshness window:
// - claim heartbeats: bead.HeartbeatTTL
// - worker sidecars: workerstatus.LivenessTTL
// - run-state files: their ExpiresAt timestamp
//
// Stale records are ignored.
func Collect(projectRoot string, store *bead.Store, now time.Time) (Snapshot, error) {
	byKey := make(map[string]Record)

	add := func(rec Record) {
		key := activeWorkKey(rec)
		if key == "" {
			return
		}
		if existing, ok := byKey[key]; ok {
			byKey[key] = mergeRecord(existing, rec)
			return
		}
		byKey[key] = rec
	}

	if store != nil {
		beads, err := store.ReadAll(context.Background())
		if err != nil {
			return Snapshot{}, err
		}
		for _, b := range beads {
			if b.Status != bead.StatusOpen && b.Status != bead.StatusInProgress {
				continue
			}
			lease, found, err := store.ClaimLease(b.ID)
			if err != nil || !found || lease.UpdatedAt.IsZero() {
				continue
			}
			if now.Sub(lease.UpdatedAt) > bead.HeartbeatTTL {
				continue
			}
			add(Record{
				BeadID:         b.ID,
				WorkerID:       lease.Owner,
				Owner:          lease.Owner,
				Source:         "claim",
				LastActivityAt: lease.UpdatedAt.UTC(),
			})
		}
	}

	if projectRoot != "" {
		liveness, err := workerstatus.ListLiveness(projectRoot)
		if err != nil {
			return Snapshot{}, err
		}
		for _, rec := range liveness {
			if !rec.IsFresh(now) {
				continue
			}
			if rec.PID > 0 && !processAlive(rec.PID) {
				continue
			}
			add(Record{
				WorkerID:       rec.WorkerID,
				BeadID:         rec.CurrentBead,
				AttemptID:      rec.AttemptID,
				Phase:          rec.Phase,
				Source:         "liveness",
				LastActivityAt: rec.LastActivityAt.UTC(),
			})
		}

		states, err := agent.ReadRunStates(projectRoot)
		if err != nil {
			return Snapshot{}, err
		}
		for _, state := range states {
			if !state.ExpiresAt.IsZero() && now.After(state.ExpiresAt) {
				continue
			}
			if state.PID > 0 && !processAlive(state.PID) {
				continue
			}
			add(Record{
				BeadID:         state.BeadID,
				AttemptID:      state.AttemptID,
				Source:         "run-state",
				LastActivityAt: state.RefreshedAt.UTC(),
			})
		}
	}

	records := make([]Record, 0, len(byKey))
	beadIDs := make(map[string]struct{})
	for _, rec := range byKey {
		records = append(records, rec)
		if rec.BeadID != "" {
			beadIDs[rec.BeadID] = struct{}{}
		}
	}

	sort.SliceStable(records, func(i, j int) bool {
		if records[i].LastActivityAt.Equal(records[j].LastActivityAt) {
			if records[i].BeadID == records[j].BeadID {
				if records[i].AttemptID == records[j].AttemptID {
					if records[i].WorkerID == records[j].WorkerID {
						return records[i].Source < records[j].Source
					}
					return records[i].WorkerID < records[j].WorkerID
				}
				return records[i].AttemptID < records[j].AttemptID
			}
			return records[i].BeadID < records[j].BeadID
		}
		return records[i].LastActivityAt.After(records[j].LastActivityAt)
	})

	beadList := make([]string, 0, len(beadIDs))
	for id := range beadIDs {
		beadList = append(beadList, id)
	}
	sort.Strings(beadList)

	return Snapshot{
		Count:   len(records),
		BeadIDs: beadList,
		Records: records,
	}, nil
}

func activeWorkKey(rec Record) string {
	switch {
	case rec.BeadID != "":
		return "bead:" + rec.BeadID
	case rec.AttemptID != "":
		return "attempt:" + rec.AttemptID
	case rec.WorkerID != "":
		return "worker:" + rec.WorkerID
	default:
		return ""
	}
