package agent

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/DocumentDrivenDX/ddx/internal/gitrepohealth"
	agentlib "github.com/easel/fizeau"
)

const (
	// Lifecycle classifiers run in an isolated scratch workdir and are guarded by
	// a project-root dirtiness check. Use Fizeau's supported safe permission band
	// so unpinned auto-routing can choose a route; the reviewer path keeps the
	// stricter internal readonly marker.
	PermissionsReadOnlyLifecycle = "safe"
	lifecycleScratchDirPrefix    = "ddx-lifecycle-"
)

type lifecycleProjectStatusSnapshot struct {
	available bool
	entries   map[string]string
}

func dispatchLifecycleRun(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
	scratchDir, err := newLifecycleScratchDir(projectRoot)
	if err != nil {
		return nil, fmt.Errorf("lifecycle dispatch: create scratch workdir: %w", err)
	}
	defer func() {
		// Deregister the seeded worktree (no-op/ignored if the fallback empty
		// repo was used) before removing the directory, so it does not linger
		// in the project's worktree registry.
		_ = internalgit.Command(context.Background(), projectRoot, "worktree", "remove", "--force", scratchDir).Run()
		_ = os.RemoveAll(scratchDir)
	}()

	runtime.WorkDir = scratchDir
	runtime.PermissionsOverride = PermissionsReadOnlyLifecycle

	before, err := captureLifecycleProjectStatus(projectRoot)
	if err != nil {
		return nil, err
	}

	result, dispatchErr := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, runtime)

	beadID := ""
	if runtime.Correlation != nil {
		beadID = strings.TrimSpace(runtime.Correlation["bead_id"])
	}
	if guardErr := guardLifecycleProjectStatus(projectRoot, before, beadID); guardErr != nil {
		return nil, guardErr
	}
	if dispatchErr != nil {
		return nil, dispatchErr
	}
	return result, nil
}

func newLifecycleScratchDir(projectRoot string) (string, error) {
	dir, err := config.MkdirExecutionScratch(projectRoot, lifecycleScratchDirPrefix)
	if err != nil {
		return "", err
	}
	// Seed the scratch workdir from the project's HEAD so the readiness-check
	// classifier sees the project's real source files rather than an empty repo
	// — otherwise file-presence checks block every bead (ddx-efadca32). A
	// detached worktree keeps the classifier isolated from the master worktree
	// (it cannot mutate tracked files there). git worktree add must create the
	// directory itself, so clear the placeholder MkdirExecutionScratch made.
	if rmErr := os.RemoveAll(dir); rmErr != nil {
		return "", fmt.Errorf("reset lifecycle scratch dir: %w", rmErr)
	}
	if out, addErr := internalgit.Command(context.Background(), projectRoot, "worktree", "add", "--detach", dir, "HEAD").CombinedOutput(); addErr != nil {
		// HEAD may be unborn (a project with no commits yet); readiness has
		// nothing to check there, so fall back to an empty scratch repo.
		if mkErr := os.MkdirAll(dir, 0o700); mkErr != nil {
			return "", fmt.Errorf("recreate lifecycle scratch dir after worktree add failed (%s): %w", strings.TrimSpace(string(out)), mkErr)
		}
		if out2, initErr := internalgit.Command(context.Background(), dir, "init", "-q").CombinedOutput(); initErr != nil {
			_ = os.RemoveAll(dir)
			return "", fmt.Errorf("initialize lifecycle scratch git repo: %s: %w", strings.TrimSpace(string(out2)), initErr)
		}
	}
	return dir, nil
}

func captureLifecycleProjectStatus(projectRoot string) (lifecycleProjectStatusSnapshot, error) {
	if strings.TrimSpace(projectRoot) == "" {
		return lifecycleProjectStatusSnapshot{}, nil
	}
	if _, err := os.Stat(filepath.Join(projectRoot, ".git")); err != nil {
		if os.IsNotExist(err) {
			return lifecycleProjectStatusSnapshot{}, nil
		}
		return lifecycleProjectStatusSnapshot{}, fmt.Errorf("lifecycle dispatch: stat project root .git: %w", err)
	}
	repair := gitrepohealth.RepairKnownConfigCorruption(context.Background(), projectRoot)
	if !repair.StatusSucceeded {
		detail := strings.TrimSpace(firstNonEmpty(repair.StatusStderr, repair.StatusOutput))
		return lifecycleProjectStatusSnapshot{}, fmt.Errorf("lifecycle dispatch: snapshot project root dirtiness: %s", detail)
	}
	out, err := internalgit.Command(context.Background(), projectRoot, "status", "--porcelain", "--untracked-files=all").CombinedOutput()
	if err != nil {
		return lifecycleProjectStatusSnapshot{}, fmt.Errorf("lifecycle dispatch: snapshot project root dirtiness: %s: %w", strings.TrimSpace(string(out)), err)
	}
	return lifecycleProjectStatusSnapshot{
		available: true,
		entries:   parseLifecycleProjectStatus(string(out)),
	}, nil
}

func parseLifecycleProjectStatus(raw string) map[string]string {
	entries := map[string]string{}
	for _, line := range strings.Split(raw, "\n") {
		line = strings.TrimRight(line, "\r")
		if len(line) < 4 || strings.TrimSpace(line) == "" {
			continue
		}
		status := line[:2]
		path := strings.TrimSpace(line[3:])
		if idx := strings.Index(path, " -> "); idx >= 0 {
			path = strings.TrimSpace(path[idx+4:])
		}
		if path == "" {
			continue
		}
		entries[path] = status
	}
	return entries
}

func guardLifecycleProjectStatus(projectRoot string, before lifecycleProjectStatusSnapshot, beadID string) error {
	if !before.available {
		return nil
	}
	after, err := captureLifecycleProjectStatus(projectRoot)
	if err != nil {
		return err
	}
	if lifecycleProjectStatusEqual(before.entries, after.entries) {
		return nil
	}

	newPaths, changedPaths := diffLifecycleProjectStatus(before.entries, after.entries)
	if len(newPaths) > 0 {
		if err := restoreLifecycleProjectMutations(projectRoot, after.entries, newPaths); err != nil {
			return err
		}
		restored, restoreErr := captureLifecycleProjectStatus(projectRoot)
		if restoreErr != nil {
			return restoreErr
		}
		after = restored
		newPaths, changedPaths = diffLifecycleProjectStatus(before.entries, after.entries)
	}
	if len(newPaths) == 0 && len(changedPaths) == 0 {
		if beadID != "" {
			return fmt.Errorf("lifecycle dispatch: project root mutation rejected for bead %s", beadID)
		}
		return fmt.Errorf("lifecycle dispatch: project root mutation rejected")
	}

	var details []string
	if len(newPaths) > 0 {
		details = append(details, "new dirty paths: "+strings.Join(newPaths, ", "))
	}
	if len(changedPaths) > 0 {
		details = append(details, "changed existing dirty paths: "+strings.Join(changedPaths, ", "))
	}
	if beadID != "" {
		return fmt.Errorf("lifecycle dispatch: project root mutation rejected for bead %s (%s)", beadID, strings.Join(details, "; "))
	}
	return fmt.Errorf("lifecycle dispatch: project root mutation rejected (%s)", strings.Join(details, "; "))
}

func lifecycleProjectStatusEqual(left, right map[string]string) bool {
	if len(left) != len(right) {
		return false
	}
	for path, status := range left {
		if right[path] != status {
			return false
		}
	}
	return true
}

func diffLifecycleProjectStatus(before, after map[string]string) (newPaths []string, changedPaths []string) {
	for path, afterStatus := range after {
		beforeStatus, ok := before[path]
		if !ok {
			newPaths = append(newPaths, path)
			continue
		}
		if beforeStatus != afterStatus {
			changedPaths = append(changedPaths, path)
		}
	}
	for path := range before {
		if _, ok := after[path]; !ok {
			changedPaths = append(changedPaths, path)
		}
	}
	sort.Strings(newPaths)
	sort.Strings(changedPaths)
	return newPaths, changedPaths
}

func restoreLifecycleProjectMutations(projectRoot string, after map[string]string, newPaths []string) error {
	var restorePaths []string
	var cleanPaths []string
	for _, path := range newPaths {
		if after[path] == "??" {
			cleanPaths = append(cleanPaths, path)
			continue
		}
		restorePaths = append(restorePaths, path)
	}

	if len(restorePaths) > 0 {
		args := []string{"restore", "--source=HEAD", "--staged", "--worktree", "--"}
		args = append(args, restorePaths...)
		if out, err := internalgit.Command(context.Background(), projectRoot, args...).CombinedOutput(); err != nil {
			return fmt.Errorf("lifecycle dispatch: restore project root mutation: %s: %w", strings.TrimSpace(string(out)), err)
		}
	}
	if len(cleanPaths) > 0 {
		args := []string{"clean", "-fd", "--"}
		args = append(args, cleanPaths...)
		if out, err := internalgit.Command(context.Background(), projectRoot, args...).CombinedOutput(); err != nil {
			return fmt.Errorf("lifecycle dispatch: clean project root mutation: %s: %w", strings.TrimSpace(string(out)), err)
		}
	}
	return nil
}

// Package workerstatus reports on live "ddx work" / "ddx try" processes,
// scoped to a specific project root by default.
//
// Operators and agents asking "is the worker still working beads?" must be
// able to answer the question for one project at a time. A global process
// scan ("ps aux | grep ddx work") returns workers from every checkout on the
// machine and produces a misleading "yes, working" signal when the worker
// belongs to a different repository. This package filters live workers by
// the resolved project root so the answer always matches the question.
package workerstatus

import (
	"context"
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

// LiveWorker describes one running ddx worker process.
type LiveWorker struct {
	PID                int             `json:"pid"`
	Command            string          `json:"command"`
	StartedAt          time.Time       `json:"started_at"`
	AgeSeconds         float64         `json:"age_seconds"`
	Age                string          `json:"age"`
	ProjectRoot        string          `json:"project_root"`
	BeadID             string          `json:"bead_id,omitempty"`
	AttemptID          string          `json:"attempt_id,omitempty"`
	Phase              string          `json:"phase,omitempty"`
	Message            string          `json:"message,omitempty"`
	ChildPID           int             `json:"child_pid,omitempty"`
	LastActivityAt     time.Time       `json:"last_activity_at,omitempty"`
	ExecutionWorktree  string          `json:"execution_worktree,omitempty"`
	Cwd                string          `json:"cwd,omitempty"`
	ProviderChildren   []ProviderChild `json:"provider_children,omitempty"`
	StaleMonitorShells int             `json:"stale_monitor_shells,omitempty"`
}

// ProviderChild describes a provider CLI subprocess observed under a worker.
//
// RouteOwner is set when the child's provider matches the worker's active
// route/harness; such a child is legitimate route work and is never reaped.
// NonRoute is set on a provider CLI whose provider does not match the active
// route — an unrelated harness the running-phase guard terminates — and
// Diagnostic carries an operator-facing explanation for that quarantine.
type ProviderChild struct {
	PID        int     `json:"pid"`
	Provider   string  `json:"provider"`
	Harness    string  `json:"harness,omitempty"`
	RouteOwner string  `json:"route_owner,omitempty"`
	Phase      string  `json:"phase,omitempty"`
	AgeSeconds float64 `json:"age_seconds"`
	NonRoute   bool    `json:"non_route,omitempty"`
	Diagnostic string  `json:"diagnostic,omitempty"`
}

// Scanner discovers live ddx worker processes on the host.
type Scanner interface {
	Scan(ctx context.Context) ([]LiveWorker, error)
}

// New returns the platform-appropriate Scanner. On Linux this reads /proc.
// On other platforms it returns an empty list; the caller's tests and the
// --all-projects escape hatch remain meaningful regardless.
func New() Scanner {
	return newSystemScanner()
}

// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
// total) embedded in argv strings or worktree paths.
var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)

// executionWorktreePattern matches the conventional execute-bead worktree
// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
// in a path. The directory name is enough to identify the worktree even when
// the surrounding path is unconventional.
var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)

// InferBead extracts a bead ID and execution worktree path from the worker's
// command line and current working directory. It returns the longest worktree
// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
// the inline worker has chdir'd into the isolated worktree), and the first
// bead ID matched in either the command line or the worktree path.
//
// Either return value may be empty when no signal is present, which is the
// expected case for a long-running `ddx work` drain that has not yet started
// a specific bead.
func InferBead(cmdline, cwd string) (beadID, worktree string) {
	worktree = extractWorktreePath(cwd)
	if worktree == "" {
		worktree = extractWorktreePath(cmdline)
	}

	if m := beadIDPattern.FindString(worktree); m != "" {
		beadID = m
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cmdline); m != "" {
			beadID = m
		}
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cwd); m != "" {
			beadID = m
		}
	}
	return beadID, worktree
}

func extractWorktreePath(s string) string {
	if s == "" {
		return ""
	}
	if !strings.Contains(s, ".execute-bead-wt-") {
		return ""
	}
	matches := executionWorktreePattern.FindStringIndex(s)
	if matches == nil {
		return ""
	}
	start := matches[0]
	end := matches[1]
	for start > 0 {
		r := s[start-1]
		if r == ' ' || r == '\x00' || r == '\t' {
			break
		}
		start--
	}
	for end < len(s) {
		r := s[end]
		if r == ' ' || r == '\x00' || r == '\t' {
			break
		}
		end++
	}
	return s[start:end]
}

// FilterByProject returns workers whose ProjectRoot resolves to the same path
// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
// filepath.EvalSymlinks so a symlinked checkout matches its real path.
func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
	target := canonicalPath(projectRoot)
	out := make([]LiveWorker, 0, len(workers))
	for _, w := range workers {
		if SamePath(w.ProjectRoot, target) {
			out = append(out, w)
		}
	}
	return out
}

// SamePath reports whether a and b refer to the same on-disk location after
// canonicalisation. It tolerates empty inputs (returning false) so callers
// can safely compare optional fields without prefiltering.
func SamePath(a, b string) bool {
	ca := canonicalPath(a)
	cb := canonicalPath(b)
	if ca == "" || cb == "" {
		return false
	}
	return ca == cb
}

func canonicalPath(p string) string {
	if strings.TrimSpace(p) == "" {
		return ""
	}
	abs, err := filepath.Abs(p)
	if err != nil {
		abs = filepath.Clean(p)
	}
	if resolved, err := filepath.EvalSymlinks(abs); err == nil {
		return resolved
	}
	return abs
}

// FormatAge renders a duration as a short human-readable string mirroring
// the conventions used by the server-backed worker list (`5s`, `12m`,
// `1h30m`). It is intended for terminal output; JSON output uses
// AgeSeconds as the numeric source of truth.
func FormatAge(d time.Duration) string {
	if d < time.Minute {
		if d < 0 {
			d = 0
		}
		return roundedSeconds(d)
	}
	if d < time.Hour {
		return roundedMinutes(d)
	}
	hours := int(d.Hours())
	mins := int(d.Minutes()) % 60
	if mins == 0 {
		return durationHours(hours)
	}
	return durationHoursMinutes(hours, mins)
}

func roundedSeconds(d time.Duration) string {
	secs := int(d.Seconds())
	return durationSeconds(secs)
}

func roundedMinutes(d time.Duration) string {
	mins := int(d.Minutes())
	return durationMinutes(mins)
}

func durationSeconds(n int) string { return formatUnit(n, "s") }
func durationMinutes(n int) string { return formatUnit(n, "m") }
func durationHours(n int) string   { return formatUnit(n, "h") }
func durationHoursMinutes(h, m int) string {
	return formatUnit(h, "h") + formatUnit(m, "m")
}

func formatUnit(n int, unit string) string {
	if n < 0 {
		n = 0
	}
	return itoa(n) + unit
}

func itoa(n int) string {
	if n == 0 {
		return "0"
	}
	neg := n < 0
	if neg {
		n = -n
	}
	var digits [20]byte
	i := len(digits)
	for n > 0 {
		i--
		digits[i] = byte('0' + n%10)
		n /= 10
	}
	out := string(digits[i:])
	if neg {
		return "-" + out
	}
	return out
}

