			"code": personaErr.Type,
		},
	}
}

// QueueSummary is the resolver for the queueSummary field.
// InProgress counts the reconciled active-work snapshot so lifecycle state and
// active execution agree on what is actually running.
func (r *queryResolver) QueueSummary(ctx context.Context, projectID string) (*QueueSummary, error) {
	projectRoot := r.projectRoot(ctx, projectID)
	store := projectBeadStore(projectRoot)
	counts, err := store.Status()
	if err != nil {
		return nil, err
	}

	activeWork, err := activework.Collect(projectRoot, store, time.Now().UTC())
	if err != nil {
		return nil, err
	}

	return &QueueSummary{
		Ready:             counts.Ready,
		Blocked:           counts.ExternalBlocked,
		InProgress:        activeWork.Count,
		OperatorAttention: counts.OperatorAttention,
		DependencyWaiting: counts.DependencyWaiting,
		ExternalBlocked:   counts.ExternalBlocked,
		Cancelled:         counts.Cancelled,
	}, nil
}

// QueueAndWorkersSummary backs the global drain indicator (ddx-b6cf025c).
// Returns zeros — not an error — for unknown or empty projects so the nav
// component can render without special-casing failures.
func (r *queryResolver) QueueAndWorkersSummary(ctx context.Context, projectID string) (*QueueAndWorkersSummary, error) {
	out := &QueueAndWorkersSummary{}
	// Only resolve ready beads when the projectID maps to a real project.
	// Unknown IDs return zeros rather than falling back to WorkingDir so the
	// indicator does not surface an unrelated project's queue depth.
	if r.State != nil {
		if proj, ok := r.State.GetProjectSnapshotByID(projectID); ok && proj.Path != "" {
			store := projectBeadStore(proj.Path)
			if ready, err := store.Ready(); err == nil {
				out.ReadyBeads = len(ready)
			}
		}
		workers := r.State.GetWorkersGraphQL(projectID)
		out.TotalWorkers = len(workers)
		for _, w := range workers {
			if w != nil && w.State == "running" {
				out.RunningWorkers++
			}
		}
	}
	// Surface the optional workers.max_count cap so the UI can pre-emptively
	// disable the `+ Add worker` affordance rather than relying on a server
	// error from workerDispatch (ddx-b6cf025c review finding).
	if cfg, err := config.LoadWithWorkingDir(r.projectRoot(ctx, projectID)); err == nil && cfg != nil && cfg.Workers != nil && cfg.Workers.MaxCount != nil {
		v := *cfg.Workers.MaxCount
		out.MaxCount = &v
	}
	return out, nil
}

