	return executeBeadIterationOutcome{Continue: true}, nil
}
freshCandidate, staleSkip, refreshErr := w.refreshCandidateBeforeClaim(ctx, candidate)
if refreshErr != nil {
	return executeBeadIterationOutcome{Stop: true}, refreshErr
}
if staleSkip != nil {
	transientCandidateSkips[candidate.ID] = staleCandidateSkipReason
	if runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "picker skip stale candidate %s before claim: %s\n", candidate.ID, staleSkip.Detail)
	}
	emitStaleCandidateSkip(emit, candidate.ID, staleSkip, freshCandidate, "pre_claim")
	recordClaimAttempt(false, candidate.ID)
	if stopAfterNonAttemptSkip() {
		applyStop(work.StopInput{Once: true})
		return executeBeadIterationOutcome{Stop: true}, nil
	}

}
switch {
case intakeErr != nil:
	if errors.Is(intakeErr, context.Canceled) || errors.Is(intakeErr, context.DeadlineExceeded) {
		if exitReason == "" {
			applyStop(work.StopInput{ContextErr: intakeErr})
		}
		return executeBeadIterationOutcome{Stop: true}, intakeErr
	}
	warning := trimDiagnosticPrefix(intakeErr.Error(), "pre-claim intake")
	classified := ClassifyReadiness(ReadinessClassificationSystemUnready, nil, warning)
	rootMutationError := sawParentBackEdge && isProjectRootMutationRejectedDetail(warning)
	message := fmt.Sprintf("check unavailable: %s (continuing)", warning)
	eventType := "pre_claim_intake.warn"
	policyMode := "warn-only"
	decision := "warn"
	suggestedAction := "check the readiness route or harness configuration and retry"
	if rootMutationError {
		message = fmt.Sprintf("check unavailable for bead %s: %s (error)", candidate.ID, warning)
		eventType = "pre_claim_intake.error"
		policyMode = "error"
		decision = "error"
		suggestedAction = "inspect the parent back-edge and clean the project root before retrying"
	}
	if runtime.Log != nil {
		_, _ = fmt.Fprint(runtime.Log, workLog.FormatLifecycleLine(WorkLogLifecycleLine{
			Phase:    "readiness",
			BeadID:   candidate.ID,
			Message:  message,
			Harness:  harness,
			Provider: provider,
			Model:    model,
		}))
	}
	eventBody := readinessDecisionBody(
		"pre_claim_intake.system_unready",
		classified.Reason,
		"pre_claim_intake",
		policyMode,
		decision,
		suggestedAction,
		map[string]any{
			"bead_id":       candidate.ID,
			"outcome":       string(PreClaimIntakeError),
			"system_reason": classified.SystemReason,
			"detail":        warning,
		},
	)
	if rootMutationError {
		eventBody["severity"] = "error"
	}
	emit(eventType, eventBody)
	if !rootMutationError && appendPreClaimWarn(candidate.ID, "system_unready", warning, now().UTC()) {
		return executeBeadIterationOutcome{Stop: true}, nil
	}
case intakeOutcome == PreClaimIntakeActionableAtomic:
	// pass-through
case intakeOutcome == PreClaimIntakeActionableButRewritten:
	if err := applyPreClaimIntakeRewrite(w.Store, candidate.ID, assignee, intakeResult, now().UTC()); err != nil {
		warning := trimDiagnosticPrefix(err.Error(), "pre-claim intake rewrite")
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "bead readiness: rewrite error: %s (continuing with original %s)\n", warning, candidate.ID)
		}
		emit("pre_claim_intake.warn", readinessDecisionBody(
			"pre_claim_intake.rewrite_rejected",
			"rewrite_rejected",
			"pre_claim_intake",
			"warn-only",
			"warn",
			"revise the rewrite so it preserves every explicit commitment",
			map[string]any{
				"bead_id": candidate.ID,
				"outcome": string(PreClaimIntakeActionableButRewritten),
				"detail":  warning,
			},
		))

			"detail":               detail,
			"operator_override":    false,
			"prompt_fingerprint":   promptFingerprint,
			"accepted_fingerprint": findingFingerprint,
		},
	)
	body["fingerprint"] = findingFingerprint
	body["rule_fingerprint"] = findingFingerprint
	body["prompt_fingerprint"] = promptFingerprint

	if err := store.ParkToProposedWithIntakeEvent(candidate.ID, actor, string(outcome), reason, detail, body, at, func(b *bead.Bead) {
		ensureBeadExtra(b)
		b.Labels = removeBeadLabels(b.Labels, bead.LabelNeedsHuman, bead.LabelNeedsInvestigation)
		bead.SetNeedsHumanMeta(b, bead.NeedsHumanMeta{
			Reason:          reason,
			Since:           at.UTC().Format(time.RFC3339),
			Source:          "ddx work",
			SuggestedAction: "review intake result and accept, rewrite, split, block, or cancel",
			Summary:         "pre-claim intake blocked execution",
		})
	}); err != nil {
		return false, err
	}
	return true, nil
}

func appendPreClaimIntakeWarning(store ExecuteBeadLoopStore, emit func(string, map[string]any), warnState *preClaimWarnRepeatState, threshold int, beadID, actor, reason, detail string, at time.Time) bool {
	if store == nil {
		return false
	}
	fingerprint := preClaimIntakeWarningFingerprint(reason, detail)
	body := readinessDecisionBodyJSON(
		"pre_claim_intake."+strings.TrimSpace(reason),
		reason,
		"pre_claim_intake",
		"warn-only",
		"warn",
		"revise the rewrite so it preserves every explicit commitment",
		map[string]any{
			"reason": reason,
			"detail": detail,
		},
	)
	if fingerprint != "" {
		var bodyMap map[string]any
		_ = json.Unmarshal([]byte(body), &bodyMap)
		if bodyMap == nil {
			bodyMap = map[string]any{}
		}
		bodyMap["fingerprint"] = fingerprint
		bodyMap["warning_fingerprint"] = fingerprint

		eventType = "pre_claim_intake.error"
		policyMode = "error"
		decision = "error"
		suggestedAction = "inspect the parent back-edge and clean the project root before retrying"
	}
	if runtime.Log != nil {
		_, _ = fmt.Fprint(runtime.Log, workLog.FormatLifecycleLine(WorkLogLifecycleLine{
			Phase:    "readiness",
			BeadID:   candidate.ID,
			Message:  message,
			Harness:  harness,
			Provider: provider,
			Model:    model,
		}))
	}
	eventBody := readinessDecisionBody(
		"pre_claim_intake.system_unready",
		reason,
		"pre_claim_intake",
		policyMode,
		decision,
		suggestedAction,
		map[string]any{
			"bead_id":       candidate.ID,
			"outcome":       string(PreClaimIntakeError),
			"system_reason": systemReason,
			"detail":        warning,
		},
	)
	if rootMutationError {
		eventBody["severity"] = "error"
	}
	emit(eventType, eventBody)
	if !rootMutationError && appendPreClaimWarn(candidate.ID, "system_unready", warning, now().UTC()) {
		return executeBeadIterationOutcome{Stop: true}, nil
	}
case intakeOutcome == PreClaimIntakeTooLargeDecomposed:
	// too_large_decomposed should move work forward by splitting before
	// claim. Some intake classifiers only identify the need to split;
	// when no concrete children are attached, ask the orchestrator
	// decomposer for executable child specs and then apply them.
	decomp := intakeResult.Decomposition
	if decomp == nil && runtime.PostAttemptDecompositionHook != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "bead readiness requested decomposition; generating split (%s)\n", candidate.ID)
		}

		// too_large_decomposed with concrete child specs: validate the AC map,
		// check the queue-level depth cap, then create children and wire deps.
		lossyOrEmpty := isDecompositionLossy(decomp.ACMap) || (len(decomp.ACMap) == 0 && strings.TrimSpace(candidate.Acceptance) != "")
		depthAtCap := storeBeadDepth(ctx, w.Store, &candidate) >= rcfg.MaxDecompositionDepth()
		if lossyOrEmpty || depthAtCap {
			// Cannot produce a lossless split: block for operator.
			blockedDetail := "decomposition AC map is incomplete or depth cap reached; operator review required"
			if depthAtCap {
				blockedDetail = "depth cap reached during decomposition; operator must split"
			}
			if runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "bead decomposition blocked: %s (%s)\n", blockedDetail, candidate.ID)
			}
			operatorOverrideDecompBlocked, _ := detectIntakeBlockedOperatorOverride(w.Store, &candidate, "pre_claim_intake."+strings.TrimSpace(string(PreClaimIntakeOperatorRequired)), "operator_required", "pre_claim_intake", "block", "park", "review intake result and accept, rewrite, split, block, or cancel")
			emit("pre_claim_intake.blocked", map[string]any{
				"bead_id":           candidate.ID,
				"operator_override": operatorOverrideDecompBlocked,
				"outcome":           string(PreClaimIntakeOperatorRequired),
				"reason":            blockedDetail,
				"detail":            blockedDetail,
			})
			if strictIntakeBlocking() {
				if parked, berr := parkBeadPostIntakeRejection(w.Store, &candidate, assignee, PreClaimIntakeOperatorRequired, "operator_required", blockedDetail, now().UTC()); berr != nil && runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "readiness park error: %v\n", berr)
				} else if parked {
					_ = releaseWorkerClaim(w.Store, candidate.ID, assignee)
					if stopAfterNonAttemptSkip() {
						applyStop(work.StopInput{Once: true})
						return executeBeadIterationOutcome{Stop: true}, nil
					}
					return executeBeadIterationOutcome{Continue: true}, nil
				}
			} else {
				if appendPreClaimWarn(candidate.ID, "decomposition_blocked_best_effort", blockedDetail, now().UTC()) {
					return executeBeadIterationOutcome{Stop: true}, nil
				}
			}
			break
		}
		childIDs, decompErr := applyPreClaimDecomposition(ctx, w.Store, &candidate, decomp, assignee, now().UTC())
		if decompErr != nil {
			if runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "bead decomposition error: %v (%s)\n", decompErr, candidate.ID)
			}
			operatorOverrideDecompErr, _ := detectIntakeBlockedOperatorOverride(w.Store, &candidate, "pre_claim_intake."+strings.TrimSpace(string(PreClaimIntakeOperatorRequired)), "operator_required", "pre_claim_intake", "block", "park", "review intake result and accept, rewrite, split, block, or cancel")
			emit("pre_claim_intake.blocked", readinessDecisionBody(
				"pre_claim_intake."+strings.TrimSpace(string(PreClaimIntakeOperatorRequired)),
				"operator_required",
				"pre_claim_intake",
				"block",
				"park",
				"review intake result and accept, rewrite, split, block, or cancel",
				map[string]any{
					"bead_id":           candidate.ID,
					"operator_override": operatorOverrideDecompErr,
					"outcome":           string(PreClaimIntakeOperatorRequired),
					"detail":            decompErr.Error(),
				},
			))
			if strictIntakeBlocking() {
				if parked, berr := parkBeadPostIntakeRejection(w.Store, &candidate, assignee, PreClaimIntakeOperatorRequired, "operator_required", decompErr.Error(), now().UTC()); berr != nil && runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "readiness park error: %v\n", berr)
				} else if parked {
					_ = releaseWorkerClaim(w.Store, candidate.ID, assignee)
					if stopAfterNonAttemptSkip() {
						applyStop(work.StopInput{Once: true})
						return executeBeadIterationOutcome{Stop: true}, nil
					}
					return executeBeadIterationOutcome{Continue: true}, nil
				}
			} else {
				if appendPreClaimWarn(candidate.ID, "decomposition_error_best_effort", decompErr.Error(), now().UTC()) {
					return executeBeadIterationOutcome{Stop: true}, nil
				}
			}
			break
		}
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "bead decomposed into %s (releasing %s)\n", strings.Join(childIDs, ", "), candidate.ID)
		}
		emit("pre_claim_intake.decomposed", map[string]any{
			"bead_id":   candidate.ID,
			"child_ids": childIDs,
		})
		// Parent stays open (not proposed) — it is now execution-ineligible
		// and will close once the decomposed children reach terminal state.
		_ = releaseWorkerClaim(w.Store, candidate.ID, assignee)
		if stopAfterNonAttemptSkip() {
			applyStop(work.StopInput{Once: true})
			return executeBeadIterationOutcome{Stop: true}, nil
		}
		return executeBeadIterationOutcome{Continue: true}, nil
	default:
		// Terminal non-actionable intake outcomes are warnings during
		// broad queue drain: the worker should prefer making an attempt
		// and letting review/follow-up work handle gaps. Explicit
		// targeted execution keeps the stricter parking behavior.
		warning := trimDiagnosticPrefix(intakeResult.Detail, "pre-claim intake")
		if warning == "" {
			warning = string(intakeOutcome)
		}
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "bead readiness blocked: %s (%s)\n", warning, candidate.ID)
		}
		operatorOverrideTerminal, _ := detectIntakeBlockedOperatorOverride(w.Store, &candidate, "pre_claim_intake."+strings.TrimSpace(string(intakeOutcome)), intakeResult.Reason, "pre_claim_intake", "best-effort", "attempt", "continue with implementation; review should create follow-up work for remaining gaps")
		emit("pre_claim_intake.blocked", readinessDecisionBody(
			"pre_claim_intake."+strings.TrimSpace(string(intakeOutcome)),
			intakeResult.Reason,
			"pre_claim_intake",
			"best-effort",
			"attempt",
			"continue with implementation; review should create follow-up work for remaining gaps",
			map[string]any{
				"bead_id":           candidate.ID,
				"operator_override": operatorOverrideTerminal,
				"outcome":           string(intakeOutcome),
				"detail":            warning,
			},
		))
		if strictIntakeBlocking() {
			if parked, berr := parkBeadPostIntakeRejection(w.Store, &candidate, assignee, intakeOutcome, intakeResult.Reason, intakeResult.Detail, now().UTC()); berr != nil && runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "readiness park error: %v\n", berr)
			} else if parked {
				_ = releaseWorkerClaim(w.Store, candidate.ID, assignee)
				if stopAfterNonAttemptSkip() {
					applyStop(work.StopInput{Once: true})
					return executeBeadIterationOutcome{Stop: true}, nil
				}
				return executeBeadIterationOutcome{Continue: true}, nil
			}
		} else {
			if appendPreClaimWarn(candidate.ID, "readiness_best_effort", warning, now().UTC()) {
				return executeBeadIterationOutcome{Stop: true}, nil
			}
		}
	}
}

// Model-backed lint is only a dispatch gate when a block threshold is
// configured. The default warn-only path relies on readiness diagnostics
// and must not stall or add advisory event noise before real work.

package agent

import "strings"

// OperatorCancelReason marks a landing preserved because the operator
// cancelled the attempt mid-flight via /api/beads/<id>/cancel. ADR-022
// §Cancel SLA: the worker aborts at the next safe point (between LLM turns /
// git ops) and emits a preserved_for_review result with this exact reason.
const OperatorCancelReason = "operator_cancel"

// PushFailedReasonPrefix is the canonical Reason prefix written by the
// landing layer when `git push` rejects the new tip after a local merge or
// fast-forward succeeded. ClassifyExecuteBeadStatus matches on this prefix
// to map a merged-locally-but-not-pushed outcome to push_failed instead of
// success, so the bead stays open.
const PushFailedReasonPrefix = "landed locally; push failed:"

// PushConflictReasonPrefix marks a more specific failure mode than
// PushFailedReasonPrefix: the local push was rejected because the remote
// advanced, the loop attempted an automatic pull/merge to recover, and the
// merge produced a conflict the loop cannot resolve. The bead is parked for
// human review with a short cooldown rather than a year-long park.
const PushConflictReasonPrefix = "landed locally; push conflict:"

// FailureMode constants classify *why* an execution did not land cleanly.
// They are orthogonal to Outcome/Status: a single failed attempt carries one
// outcome (e.g. preserved) and one failure mode (e.g. merge_conflict) so
// measurement surfaces can aggregate failures by cause.
const (
	FailureModeContextOverflow                = "context_overflow"
	FailureModeMergeConflict                  = "merge_conflict"
	FailureModeTestFailure                    = "test_failure"
	FailureModeBuildFailure                   = "build_failure"
	FailureModeTimeout                        = "timeout"
	FailureModeAuthError                      = "auth_error"
	FailureModeNoChanges                      = "no_changes"
	FailureModeNoEvidenceProduced             = "no_evidence_produced"
	FailureModeRatchetMiss                    = "ratchet_miss"
	FailureModeNoViableProvider               = "no_viable_provider"
	FailureModeProviderConnectivity           = "provider_connectivity"
	FailureModeServerUnavailable              = "server_unavailable"
	FailureModeHarnessNotInstalled            = "harness_not_installed"
	FailureModeBlockedByPassthroughConstraint = "blocked_by_passthrough_constraint"
	FailureModeAgentPowerUnsatisfied          = "agent_power_unsatisfied"
	FailureModeLockContention                 = "lock_contention"
	FailureModeWorktreeLost                   = "worktree_lost"
	// FailureModeRouteResolutionTimeout classifies an attempt that was parked
	// because route resolution / routing preflight exceeded the configured
	// route-resolution timeout. The lease is released and the bead is flagged
	// for operator attention rather than auto-retried (ddx-d8970a7b).
	FailureModeRouteResolutionTimeout = "route_resolution_timeout"
	// FailureModeProgressWatchdog classifies an attempt the progress watchdog
	// terminated because phase-empty heartbeats (harness/model/route all empty)
	// persisted past the phase budget. The worker appeared fresh to the
	// liveness TTL while making no forward progress, so the lease is released
	// and the bead is flagged for operator attention (ddx-dc23f001, parent
	// ddx-8f2e0ebf criterion B).
	FailureModeProgressWatchdog = "progress_watchdog"
	// FailureModeConsecutiveWedge classifies a bead the consecutive-wedge guard
	// stopped re-claiming because it wedged (route_resolution_timeout or
	// progress_watchdog) on consecutive claims up to the threshold. The bead is
	// parked to proposed for operator attention so the single-threaded worker
	// keeps draining the rest of the queue instead of re-wedging the same bead
	// indefinitely (ddx-9714eaac, parent ddx-8f2e0ebf criterion E).
	FailureModeConsecutiveWedge = "consecutive_wedge"
	// FailureModeAttemptIntegrity classifies an attempt that produced commits
	// and a clean agent exit but failed DDx's structured post-agent integrity
	// validation (post-commit mutation, empty pre-commit gate evidence, or
	// uncommitted tracked changes after the implementation commit). It is
	// distinct from implementation/agent failures so operators can tell a DDx
	// validation rejection apart from a genuine task failure (ddx-725b65b4).
	FailureModeAttemptIntegrity = "attempt_integrity"
	// FailureModeLandRetry classifies land/ref/index coordination failures
	// where the implementation result is still valid and the worker should
	// retry/reconcile the landing step instead of escalating implementation.
	FailureModeLandRetry = "land_retry"
	// FailureModeLandOperatorAttention classifies land/ref/index coordination
	// failures where local staged state includes operator-owned work and must
	// be reviewed before DDx lands or retries the result.
	FailureModeLandOperatorAttention = "land_operator_attention"
	FailureModeUnknown               = "unknown"
)

// ResourceExhaustedStopMessage is the operator-visible message emitted when
// execution must stop because the host cannot safely continue draining the
// queue.
const ResourceExhaustedStopMessage = "resource exhausted after cleanup; stopping work loop"

// ClassifyFailureMode derives a failure_mode for a worker-level result from
// its outcome, exit code, and error message. Returns "" when the outcome is
// task_succeeded (success carries no failure mode). task_no_changes always
// maps to FailureModeNoChanges regardless of error text.
//
// For task_failed (or non-zero exit code), the error message is scanned for
// well-known substrings. The order matters: context/auth/timeout patterns
// are checked before generic test/build patterns so a "test timed out"
// classifies as timeout rather than test_failure. Anything unrecognised
// maps to FailureModeUnknown so aggregates never hide a missed pattern.
func ClassifyFailureMode(outcome string, exitCode int, errMsg string) string {
	switch outcome {
	case ExecuteBeadOutcomeTaskSucceeded:
		if exitCode == 0 {
			return ""
		}
		// Degenerate: success outcome with non-zero exit. Treat as unknown
		// failure rather than success so the aggregate flags the anomaly.
	case ExecuteBeadOutcomeTaskNoChanges:
		return FailureModeNoChanges
	case ExecuteBeadOutcomeTaskNoEvidence:
		return FailureModeNoEvidenceProduced
	}

	lower := strings.ToLower(errMsg)
	switch {
	case IsLockContentionError(errMsg):
		return FailureModeLockContention
	case IsWorktreeLostError(errMsg):
		return FailureModeWorktreeLost
	case containsAny(lower,
		"passthrough constraint unsatisfiable",
		"passthrough constraint:",
		"max_power is less than min_power",
		"max_power exceeds min_power",
		"must be less than max_power",
		"no viable routing candidate for pins",
		"harness cannot satisfy power constraint",
		"harness pin incompatible with power bounds",
		"model pin incompatible with power bounds",
		"provider pin incompatible with power bounds"):
		return FailureModeBlockedByPassthroughConstraint
	case containsAny(lower,
		"agent power unsatisfied",
		"no model meets min_power",
		"no model with power >=",
		"minimum power not achievable",
		"min_power constraint cannot be satisfied"):
		return FailureModeAgentPowerUnsatisfied
	case containsAny(lower,
		"executable file not found in $path",
		"executable file not found",
		"no such file or directory") &&
		containsAny(lower, "exec:", "harness", "claude", "agent", "codex", "gemini"):
		return FailureModeHarnessNotInstalled
	case containsAny(lower,
		"no viable harness",
		"no harness configured",
		"failed to initialize routing service",
		"resolveroute:",
		"no viable routing candidate",
		"no live provider supports",
		"no candidate satisfying local endpoint",
		"no viable provider"):
		return FailureModeNoViableProvider
	case isServerTransportFailureText(lower):
		return FailureModeServerUnavailable
	case containsAny(lower,
		"context length",
		"context_length_exceeded",
		"context window",
		"maximum context",
		"prompt is too long",
		"prompt too long",
		"token limit",
		"too many tokens",
		"exceeds the context"):
		return FailureModeContextOverflow
	case containsAny(lower,
		"unauthorized",
		"401 unauthorized",
		"invalid api key",
		"invalid_api_key",
		"authentication failed",
		"authentication_error",
		"no api key",
		"missing api key",
		"quota exceeded",
		"insufficient quota",
		"insufficient_quota",
		"rate limit",
		"rate_limit",
		"429"):
		return FailureModeAuthError
	case containsAny(lower,
		"timeout",
		"timed out",
		"context deadline exceeded",
		"deadline exceeded",
		"signal: killed"):
		return FailureModeTimeout
	case containsAny(lower,
		"merge conflict",
		"ff-merge not possible",
		"merge failed",
		"automatic merge failed"):
		return FailureModeMergeConflict
	case containsAny(lower,
		"build failed",
		"compilation failed",
		"compile error",
		"compilation error",
		"cannot find package",
		"undefined:",
		"undefined reference",
		"syntax error"):
		return FailureModeBuildFailure
	case containsAny(lower,
		"test failed",
		"tests failed",
		"--- fail:",
		"assertion failed",
		"test failure"):
		return FailureModeTestFailure
	}
	if outcome == ExecuteBeadOutcomeTaskFailed && errMsg != "" {
		return FailureModeUnknown
	}
	if exitCode != 0 {
		return FailureModeUnknown
	}
	return ""

package agent

// execute_bead_dangling_success_test.go — regression tests for ddx-2b2d114e.
//
// AC1: success-outcome propagation is recoverable on retry; not silent no_evidence.
// AC2: regression test simulates a finalize failure and asserts the bead lands
//      cleanly on retry.

import (
