// removeEvidenceDir stages tracked files for deletion via git rm, then
// removes any remaining files with os.RemoveAll.
func (m *ExecutionCleanupManager) removeEvidenceDir(ctx context.Context, dirPath string, summary *ExecutionCleanupSummary) {
	if m.ProjectRoot == "" {
		_ = os.RemoveAll(dirPath)
		return
	}
	rel, err := filepath.Rel(m.ProjectRoot, dirPath)
	if err != nil || strings.HasPrefix(rel, "..") {
		_ = os.RemoveAll(dirPath)
		return
	}
	relSlash := filepath.ToSlash(rel)

	// Check for tracked files; if any, stage their deletion via git rm.
	lsOut, lsErr := internalgit.Command(ctx, m.ProjectRoot, "ls-files", relSlash).Output()
	if lsErr == nil && len(strings.TrimSpace(string(lsOut))) > 0 {
		rmOut, rmErr := internalgit.Command(ctx, m.ProjectRoot, "rm", "-rf", relSlash).CombinedOutput()
		if rmErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    dirPath,
				Class:   "evidence_dir_git_rm",
				Message: fmt.Sprintf("git rm: %s: %v", strings.TrimSpace(string(rmOut)), rmErr),
			})
		}
	}
	// Remove remaining untracked files.
	_ = os.RemoveAll(dirPath)
}

// pruneAgentLogs deletes .ddx/agent-logs/agent-*.jsonl and svc-*.jsonl files
// whose mtime is older than m.RetainDays. Files whose session_id matches an
// active run-state are skipped. No-op when RetainDays == 0.
func (m *ExecutionCleanupManager) pruneAgentLogs(ctx context.Context, summary *ExecutionCleanupSummary, runStates []RunState, now time.Time) {
	if m.RetainDays == 0 {
		return
	}
	if ctx != nil && ctx.Err() != nil {
		return
	}
	cutoff := now.AddDate(0, 0, -m.RetainDays)

	activeSessions := map[string]struct{}{}
	for _, rs := range runStates {
		if rs.SessionID != "" {
			activeSessions[rs.SessionID] = struct{}{}
		}
	}

	root := ddxroot.JoinProject(m.ProjectRoot, "agent-logs")
	entries, err := os.ReadDir(root)
	if err != nil {
		if !errors.Is(err, os.ErrNotExist) {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    root,
				Class:   "agent_log_read",
				Message: err.Error(),
			})
		}
		return
	}

	for _, entry := range entries {
		if ctx != nil && ctx.Err() != nil {
			return
		}
		if entry.IsDir() {
			continue
		}
		name := entry.Name()
		var sessionID string
		switch {
		case strings.HasPrefix(name, "agent-") && strings.HasSuffix(name, ".jsonl"):
			sessionID = strings.TrimSuffix(strings.TrimPrefix(name, "agent-"), ".jsonl")
		case strings.HasPrefix(name, "svc-") && strings.HasSuffix(name, ".jsonl"):
			sessionID = strings.TrimSuffix(strings.TrimPrefix(name, "svc-"), ".jsonl")
		default:
			continue
		}
		if _, ok := activeSessions[sessionID]; ok {
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    filepath.ToSlash(filepath.Join(".ddx/agent-logs", name)),
				Class:   "preserved_active_agent_log",
				Message: "active run-state session reference",
			})
			continue
		}
		info, infoErr := entry.Info()
		if infoErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    filepath.Join(root, name),
				Class:   "agent_log_stat",
				Message: infoErr.Error(),
			})
			continue
		}
		if !info.ModTime().Before(cutoff) {
			continue
		}
		path := filepath.Join(root, name)
		if !m.DryRun {
			if err := os.Remove(path); err != nil {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    path,
					Class:   "agent_log_remove",
					Message: err.Error(),
				})
				continue
			}
		}

		}
		if !isPathWithin(proc.Worktree, m.tempRoot()) {
			continue
		}

		meta, err := ReadExecutionCleanupMetadata(proc.Worktree)
		candidateRunStates := runStates
		var matchedRunState *RunState

		switch {
		case err == nil:
			if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
				// Registered worktrees are active project state and are preserved
				// even when the run-state file has already gone stale.
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    proc.Worktree,
					Class:   "preserved_registered_worktree_process",
					Message: "registered worktree is still active",
				})
				continue
			}
			if meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot) {
				if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, proc.Worktree) {
					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
						Path:    proc.Worktree,
						Class:   "preserved_foreign_project_process",
						Message: fmt.Sprintf("foreign project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
					})
					continue
				}
				candidateRunStates = m.runStatesForMetadata(meta, runStates, summary)
			}
			matchedRunState = matchingRunStateForMeta(candidateRunStates, meta)
		case errors.Is(err, os.ErrNotExist):
			if _, ok := registered[filepath.Clean(proc.Worktree)]; ok {
				// Registered worktree without metadata stays conservative and
				// does not get reaped from the process census alone.
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    proc.Worktree,
					Class:   "preserved_registered_missing_metadata_process",
					Message: "registered worktree without cleanup metadata",
				})
				continue
			}
			matchedRunState = matchingRunStateForMeta(runStates, ExecutionCleanupMetadata{WorktreePath: proc.Worktree})
			if matchedRunState == nil {
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    proc.Worktree,
					Class:   "preserved_uncertain_attempt_process",
					Message: "no live run-state or cleanup metadata matched",
				})
				continue
			}
			meta = candidateCycleMetadataFromRunState(*matchedRunState)
			meta.ProjectRoot = m.ProjectRoot
		default:
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    proc.Worktree,
				Class:   "attempt_process_metadata_read",
				Message: err.Error(),
			})
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    proc.Worktree,
				Class:   "preserved_uncertain_attempt_process",
				Message: err.Error(),
			})
			continue
		}

		live, reason := probe.IsLive(meta, matchedRunState, now)
		if live {
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    proc.Worktree,
				Class:   "preserved_live_attempt_process",
				Message: reason,
			})
			return ExecutionCleanupProcessFinding{}, false, nil
		}

		if staleProc == nil {
			staleCopy := proc
			staleProc = &staleCopy
			staleMeta = meta
			staleReason = reason
		}
	}

	if staleProc == nil {
		return ExecutionCleanupProcessFinding{}, false, nil
	}

	finding := ExecutionCleanupProcessFinding{
		PID:         staleProc.PID,
		PPID:        staleProc.PPID,
		PGID:        staleProc.PGID,
		BeadID:      staleMeta.BeadID,
		AttemptID:   staleMeta.AttemptID,
		Command:     staleProc.Command,
		Cwd:         staleProc.Cwd,
		Worktree:    staleProc.Worktree,
		StartedAt:   staleProc.StartedAt,
		StaleReason: staleReason,
		WouldKill:   true,
		Members:     make([]ExecutionCleanupProcessFact, 0, len(group)),
	}
	if finding.PGID <= 0 {
		finding.PGID = finding.PID
	}
	for _, proc := range group {
		finding.Members = append(finding.Members, ExecutionCleanupProcessFact(proc))
	}
	return finding, true, nil
}

