		if worker.BeadID != "" && worker.BeadID == meta.BeadID {
			return true
		}
		if worker.ExecutionWorktree != "" && meta.WorktreePath != "" && workerstatus.SamePath(worker.ExecutionWorktree, meta.WorktreePath) {
			return true
		}
	}
	return false
