func TestDanglingSuccess_RecoverFromResultRevAlreadyMerged(t *testing.T) {
	projectRoot, beadID := newExecuteLoopProjectRoot(t)
	ddxDir := filepath.Join(projectRoot, ddxroot.DirName)

