type claimSuccessRateWarningStore struct {
	*bead.Store
	attempts atomic.Int32
	cancel   context.CancelFunc
}

func (s *claimSuccessRateWarningStore) Claim(id, assignee string) error {
	return s.claim(id, assignee, "", "")
}

func (s *claimSuccessRateWarningStore) ClaimWithOptions(id, assignee, session, worktree string) error {
	return s.claim(id, assignee, session, worktree)
}

func (s *claimSuccessRateWarningStore) claim(id, assignee, session, worktree string) error {
	attempt := s.attempts.Add(1)
	switch attempt {
	case 1, 2, 3, 5:
		if attempt == 5 && s.cancel != nil {
			defer s.cancel()
		}
		return fmt.Errorf("synthetic claim failure %d", attempt)
	default:
		return s.Store.ClaimWithOptions(id, assignee, session, worktree)
	}
}

// TestLoop_StaysAliveWithEmptyQueue covers watch mode: the loop must
// NOT exit when nextCandidate returns no
// eligible bead. It must reset the per-Run attempted/hookFailed maps and
// sleep, then poll again. Cancelling the context is the only way out.
func TestLoop_StaysAliveWithEmptyQueue(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatalf("executor must not run on an empty queue")
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	// Use a tiny poll interval so the test runs quickly; cancel after enough
	// wall-clock for several empty-poll cycles to confirm the loop is still
	// running and not bailing out after the first empty poll.
	ctx, cancel := context.WithCancel(context.Background())
	pollInterval := 5 * time.Millisecond
	cancelAfter := 50 * time.Millisecond
	go func() {
		time.Sleep(cancelAfter)
		cancel()
	}()

	start := time.Now()
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:         executeloop.ModeWatch,
		IdleInterval: pollInterval,
	})
	elapsed := time.Since(start)

	// Context cancellation surfaces as the returned error. The key
	// invariant: the loop survived past the first empty poll.
	require.ErrorIs(t, err, context.Canceled)
	require.NotNil(t, result)
	assert.Equal(t, 0, result.Attempts)
	assert.True(t, elapsed >= cancelAfter,
		"loop must run until ctx cancellation; ran for %s, expected >= %s", elapsed, cancelAfter)
}

func TestLoop_BinaryRefreshStopsBeforeClaim(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatalf("executor must not run after binary refresh requests a restart")
			return ExecuteBeadReport{}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	checks := 0
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Mode: executeloop.ModeDrain,
		BinaryRefreshCheck: func(ctx context.Context) (bool, error) {
			checks++
			return true, nil
		},
	})

	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, 1, checks)
	assert.Equal(t, 0, result.Attempts)
	assert.Equal(t, "BinaryRefresh", result.StopCondition)
	assert.Equal(t, "binary_refresh", result.ExitReason)
	got, err := store.Get(context.Background(), first.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status)
}

func TestWorkWatch_SystemicPreClaimErrorIdlesWithoutCooldown(t *testing.T) {
	store, first, second := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatalf("executor must not run while pre-claim hook is systemically blocked")
			return ExecuteBeadReport{}, nil
		}),
	}

	ctx, cancel := context.WithCancel(context.Background())
	progressCh := make(chan ProgressEvent, 8)
	done := make(chan struct{})
	go func() {
		for {
			select {
			case evt := <-progressCh:
				if evt.Phase == "loop.idle" && evt.Message == "preclaim_systemic" {
					cancel()
					return
				}
			case <-done:
				return
			}
		}
	}()
	defer close(done)

	var logBuf bytes.Buffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:         executeloop.ModeWatch,
		IdleInterval: time.Hour,
		Log:          &logBuf,
		ProgressCh:   progressCh,
		PreClaimHook: func(ctx context.Context) error {
			return fmt.Errorf("local branch main has diverged from origin (local=abc origin=def); reconcile manually before claiming")
		},
	})

	require.ErrorIs(t, err, context.Canceled)
	require.NotNil(t, result)
	assert.Equal(t, 0, result.Attempts)
	assert.Equal(t, 0, result.Failures)

	gotFirst, err := store.Get(context.Background(), first.ID)
	require.NoError(t, err)
	gotSecond, err := store.Get(context.Background(), second.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, gotFirst.Status)
	assert.Equal(t, bead.StatusOpen, gotSecond.Status)
	assert.Nil(t, gotFirst.Extra["work-retry-after"])
	assert.Nil(t, gotSecond.Extra["work-retry-after"])

	out := logBuf.String()
	assert.Contains(t, out, "systemic; leaving beads untouched")
	assert.Contains(t, out, "pre-claim hook blocked queue:")
	assert.Equal(t, 1, strings.Count(out, "systemic; leaving beads untouched"))
}

// TestPreClaimWarnSameFingerprintEscalatesAfterThreshold verifies that the
// loop escalates repeated identical pre-claim warn fingerprints across
// distinct bead IDs, stops before claiming the threshold bead, and leaves the
// remaining ready queue untouched.
func TestPreClaimWarnSameFingerprintEscalatesAfterThreshold(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))
	beadIDs := []string{
		"ddx-preclaim-warn-1",
		"ddx-preclaim-warn-2",
		"ddx-preclaim-warn-3",
		"ddx-preclaim-warn-4",
		"ddx-preclaim-warn-5",
	}
	for i, beadID := range beadIDs {
		require.NoError(t, store.Create(context.Background(), &bead.Bead{
			ID:       beadID,
			Title:    "warn bead " + beadID,
			Priority: i,
		}))
	}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				ResultRev: "rev-" + beadID,
			}, nil
		}),
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	var eventSink, logBuf bytes.Buffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                        executeloop.ModeDrain,
		Log:                         &logBuf,
		EventSink:                   &eventSink,
		NoReview:                    true,
		PreClaimWarnRepeatThreshold: DefaultPreClaimWarnRepeatThreshold,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeError,
				Reason:  "system_unready",
				Detail:  "shared readiness schema mismatch",
			}, nil
		},
	})

	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, len(beadIDs)-1, result.Attempts)
	assert.Equal(t, len(beadIDs)-1, result.Successes)
	assert.Equal(t, 0, result.Failures)
	require.NotNil(t, result.OperatorAttention)
	assert.Equal(t, "preclaim_warn_repeated", result.OperatorAttention.Reason)
	assert.Equal(t, beadIDs[len(beadIDs)-1], result.OperatorAttention.BeadID)
	assert.Equal(t, "operator_attention", result.ExitReason)
	assert.Equal(t, "OperatorAttention", result.StopCondition)

	for _, beadID := range beadIDs[:len(beadIDs)-1] {
		got, err := store.Get(context.Background(), beadID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusClosed, got.Status)
		assert.Nil(t, got.Extra["work-retry-after"])

		assert.Nil(t, got.Extra["work-retry-after"])
	}
	lastBead, err := store.Get(context.Background(), beadIDs[len(beadIDs)-1])
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, lastBead.Status)

	lines := strings.Split(strings.TrimSpace(eventSink.String()), "\n")
	var escalations []map[string]any
	for _, line := range lines {
		if strings.TrimSpace(line) == "" {
			continue
		}
		var entry map[string]any
		require.NoError(t, json.Unmarshal([]byte(line), &entry))
		if entry["type"] != "loop.operator_attention" {
			continue
		}
		data, ok := entry["data"].(map[string]any)
		require.True(t, ok)
		if data["reason"] == "preclaim_warn_repeated" {
			escalations = append(escalations, data)
		}
	}
	require.Len(t, escalations, 1, "exactly one repeated-warn escalation is expected")
	esc := escalations[0]
	assert.NotEmpty(t, esc["fingerprint"])
	assert.Equal(t, float64(DefaultPreClaimWarnRepeatThreshold), esc["count"])
	distinctIDs, ok := esc["distinct_bead_ids"].([]any)
	require.True(t, ok, "distinct_bead_ids must be a JSON array")
	assert.Len(t, distinctIDs, DefaultPreClaimWarnRepeatThreshold)
	assert.Equal(t, "preclaim_warn_repeated", esc["reason"])
	assert.Equal(t, "shared readiness schema mismatch", esc["example_detail"])
	assert.NotEmpty(t, esc["example_payload"])

	lastEvents, err := store.Events(beadIDs[len(beadIDs)-1])
	require.NoError(t, err)
	var operatorAttentionEvent *bead.BeadEvent
	for i := range lastEvents {
		if lastEvents[i].Kind == "operator_attention" && lastEvents[i].Summary == "preclaim_warn_repeated" {
			operatorAttentionEvent = &lastEvents[i]
			break
		}
	}
	require.NotNil(t, operatorAttentionEvent, "a durable operator_attention event must be recorded")
	var body map[string]any
	require.NoError(t, json.Unmarshal([]byte(operatorAttentionEvent.Body), &body))
	assert.Equal(t, "preclaim_warn_repeated", body["reason"])
	assert.Equal(t, "shared readiness schema mismatch", body["example_detail"])
	assert.Equal(t, float64(DefaultPreClaimWarnRepeatThreshold), body["count"])
	assert.NotEmpty(t, body["fingerprint"])
}

func TestPreClaimWarnProjectRootMutationUsesStableCodeAndFingerprint(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))

	first := &bead.Bead{ID: "ddx-preclaim-root-mutation-1", Title: "root mutation 1"}
	second := &bead.Bead{ID: "ddx-preclaim-root-mutation-2", Title: "root mutation 2"}
	require.NoError(t, store.Create(context.Background(), first))
	require.NoError(t, store.Create(context.Background(), second))

	warningA := "readiness route unavailable: lifecycle dispatch: project root mutation rejected for bead " + first.ID + " (new dirty paths: alpha.txt)"
	warningB := "readiness route unavailable: lifecycle dispatch: project root mutation rejected for bead " + second.ID + " (new dirty paths: beta.txt)"

	fpA := preClaimIntakeWarningFingerprint("system_unready", warningA)
	fpB := preClaimIntakeWarningFingerprint("system_unready", warningB)
	require.NotEmpty(t, fpA)
	assert.Equal(t, fpA, fpB, "project-root mutation rejections must dedupe across bead IDs")
	assert.Equal(t, preClaimIntakeWarningCodeProjectRootMutationRejected, preClaimIntakeWarningCode("system_unready", warningA))

	warnState := &preClaimWarnRepeatState{}
	now := time.Now().UTC()
	escalated := appendPreClaimIntakeWarning(store, nil, warnState, 3, first.ID, "worker", "system_unready", warningA, now)
	require.False(t, escalated)
	escalated = appendPreClaimIntakeWarning(store, nil, warnState, 3, second.ID, "worker", "system_unready", warningB, now.Add(time.Second))
	require.False(t, escalated)
	assert.Equal(t, 2, warnState.Count)
	assert.Equal(t, []string{first.ID, second.ID}, warnState.DistinctBeadIDs)

	events, err := store.Events(first.ID)
	require.NoError(t, err)
	require.NotEmpty(t, events)
	var body map[string]any
	require.NoError(t, json.Unmarshal([]byte(events[0].Body), &body))
	assert.Equal(t, preClaimIntakeWarningCodeProjectRootMutationRejected, body["warning_code"])
}

func TestExecuteBeadLoop_NiflheimEvidence_RepeatedPreClaimSystemWarningBecomesOperatorAttention(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))

	beadIDs := []string{
		"ddx-niflheim-system-unready-1",
		"ddx-niflheim-system-unready-2",
	}
	for i, beadID := range beadIDs {
		require.NoError(t, store.Create(context.Background(), &bead.Bead{
			ID:       beadID,
			Title:    "niflheim pre-claim warning " + beadID,
			Priority: i,
		}))
	}

	var floorCalls atomic.Int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				ResultRev: "rev-" + beadID,
			}, nil
		}),
		EscalationNextFloor: func(actualPower int) (int, error) {
			floorCalls.Add(1)
			return actualPower + 1, nil
		},
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	var eventSink bytes.Buffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	detail := "readiness check timed out after 45s (.ddx/harness-sessions/session-timeout.json)"
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                        executeloop.ModeDrain,
		EventSink:                   &eventSink,
		NoReview:                    true,
		PreClaimWarnRepeatThreshold: 2,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome:      PreClaimIntakeError,
				Reason:       "system_unready",
				SystemReason: "readiness_timeout",
				Detail:       detail,
			}, nil
		},
	})

	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, 1, result.Attempts)
	assert.Equal(t, 1, result.Successes)
	assert.Equal(t, 0, result.Failures)
	require.NotNil(t, result.OperatorAttention)
	assert.Equal(t, "preclaim_warn_repeated", result.OperatorAttention.Reason)
	assert.Equal(t, beadIDs[1], result.OperatorAttention.BeadID)
	assert.Equal(t, "operator_attention", result.ExitReason)
	assert.Equal(t, "OperatorAttention", result.StopCondition)
	assert.Zero(t, floorCalls.Load(), "pre-claim system warnings must not request stronger power")

	gotFirst, err := store.Get(context.Background(), beadIDs[0])
	require.NoError(t, err)
	gotSecond, err := store.Get(context.Background(), beadIDs[1])
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, gotFirst.Status)
	assert.Equal(t, bead.StatusOpen, gotSecond.Status)
	assert.Nil(t, gotFirst.Extra["work-retry-after"])
	assert.Nil(t, gotSecond.Extra["work-retry-after"])

	lines := strings.Split(strings.TrimSpace(eventSink.String()), "\n")
	var escalations []map[string]any
	for _, line := range lines {
		if strings.TrimSpace(line) == "" {
			continue
		}
		var entry map[string]any
		require.NoError(t, json.Unmarshal([]byte(line), &entry))
		if entry["type"] != "loop.operator_attention" {
			continue
		}
		data, ok := entry["data"].(map[string]any)
		require.True(t, ok)
		if data["reason"] == "preclaim_warn_repeated" {
			escalations = append(escalations, data)
		}
	}
	require.Len(t, escalations, 1, "exactly one repeated-warn escalation is expected")
	esc := escalations[0]
	assert.NotEmpty(t, esc["fingerprint"])
	assert.Equal(t, float64(2), esc["count"])
	assert.Equal(t, beadIDs[0], esc["example_bead_id"])
	assert.Equal(t, detail, esc["example_detail"])
	distinctIDs, ok := esc["distinct_bead_ids"].([]any)
	require.True(t, ok, "distinct_bead_ids must be a JSON array")
	assert.Len(t, distinctIDs, 2)
	assert.Equal(t, "preclaim_warn_repeated", esc["reason"])
	assert.NotEmpty(t, esc["example_payload"])
	assert.Contains(t, eventSink.String(), "\"system_reason\":\"readiness_timeout\"")
	assert.Contains(t, eventSink.String(), detail)

	lastEvents, err := store.Events(beadIDs[1])
	require.NoError(t, err)
	var operatorAttentionEvent *bead.BeadEvent
	for i := range lastEvents {
		if lastEvents[i].Kind == "operator_attention" && lastEvents[i].Summary == "preclaim_warn_repeated" {
			operatorAttentionEvent = &lastEvents[i]
			break
		}
	}
	require.NotNil(t, operatorAttentionEvent, "a durable operator_attention event must be recorded")
	assert.Contains(t, operatorAttentionEvent.Body, "preclaim_warn_repeated")
	assert.Contains(t, operatorAttentionEvent.Body, detail)
}

// TestWorkWatch_PreClaimIdleEscalatesAfterRepeatedSameDetail covers
// ddx-df77e668 AC #3: when the worker idles on the same pre-claim blocker for
// preClaimIdleEscalationThreshold consecutive cycles, it emits a non-terminal
// loop.operator_attention event carrying the bead-id, detail, and elapsed-idle
// instead of looping silently. The beads are never cooldowned, and the loop
// keeps idling (the escalation does not stop the worker).
func TestWorkWatch_PreClaimIdleEscalatesAfterRepeatedSameDetail(t *testing.T) {
	store, first, second := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Errorf("executor must not run while pre-claim idles")
			return ExecuteBeadReport{}, nil
		}),
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	progressCh := make(chan ProgressEvent, 256)
	done := make(chan struct{})
	var idleCount int32
	go func() {
		for {
			select {
			case evt := <-progressCh:
				if evt.Phase == "loop.idle" && evt.Message == preClaimIdleReasonTrackerContention {
					if atomic.AddInt32(&idleCount, 1) >= int32(preClaimIdleEscalationThreshold)+2 {
						cancel()
						return
					}
				}
			case <-done:
				return
			}
		}
	}()
	defer close(done)

	var eventSink, logBuf bytes.Buffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:         executeloop.ModeWatch,
		IdleInterval: time.Millisecond,
		Log:          &logBuf,
		EventSink:    &eventSink,
		ProgressCh:   progressCh,
		SessionID:    "sess-escalate",
		WorkerID:     "worker-escalate",
		PreClaimHook: func(ctx context.Context) error {
			return errors.New("landing worktree has staged changes after waiting 2s:\nM\t.ddx/beads.jsonl\nM\t.ddx/metrics/attempts.jsonl")
		},
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", MaxDecompositionDepth: 3}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Log:                &log,
		EventSink:          &eventSink,
		PreClaimIntakeHook: hook,
		PostAttemptDecompositionHook: func(ctx context.Context, beadID string) (*PreClaimDecomposition, error) {
			require.Equal(t, parent.ID, beadID)
			return &PreClaimDecomposition{
				Rationale: "split the parent for the back-edge regression",
				Children: []PreClaimDecompositionChild{
					{
						Title:       "Child A",
						Description: "child should not depend on the parent",
						Acceptance:  "1. do child work",
					},
				},
				ACMap: []ACMapEntry{
					{
						ParentAC: "1. split into children without wiring them back to the parent",
						Coverage: "covered by Child A",
					},
				},
			}, nil
		},
		ProjectRoot: root,
		SessionID:   "sess-root-mutation-back-edge",
		WorkerID:    "worker-root-mutation-back-edge",
	})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, 2, result.Attempts, "the worker must process the back-edge bead and the root-mutation bead")

	events := parseLoopEvents(t, eventSink.String())
	sawBackEdge := strings.Contains(eventSink.String(), "\"event\":\"post_attempt_decomposition.parent_back_edge\"")
	var rootMutationError *loopEvent
	var sawWarnForLater bool
	for i := range events {
		switch events[i].Type {
		case "pre_claim_intake.warn":
			if data, ok := events[i].Data["bead_id"].(string); ok && data == later.ID {
				sawWarnForLater = true
			}
		case "pre_claim_intake.error":
			if data, ok := events[i].Data["bead_id"].(string); ok && data == later.ID {
				rootMutationError = &events[i]
			}
		}
	}
	require.Truef(t, sawBackEdge, "the run must first record the parent-back-edge state; events=%s", eventSink.String())
	require.NotNil(t, rootMutationError, "the root-mutation rejection must be surfaced as an error event")
	assert.Equal(t, "error", rootMutationError.Data["severity"])
	assert.Equal(t, "error", rootMutationError.Data["decision"])
	assert.Equal(t, "error", rootMutationError.Data["policy_mode"])
	assert.Equal(t, preClaimIntakeWarningCodeProjectRootMutationRejected, rootMutationError.Data["warning_code"])
	assert.Contains(t, fmt.Sprint(rootMutationError.Data["detail"]), "project root mutation rejected for bead "+later.ID)
	assert.Contains(t, fmt.Sprint(rootMutationError.Data["detail"]), later.ID)
	assert.Contains(t, log.String(), "check unavailable for bead "+later.ID)
	assert.Contains(t, log.String(), "(error)")
	assert.False(t, sawWarnForLater, "the root-mutation rejection must not be downgraded to a warning event")
}

func TestPreClaimIntakeHookWithLogDoesNotEmitPromptByDefault(t *testing.T) {
	root := newPreClaimIntakeHookTestRoot(t)
	store, b := newPreClaimIntakeHookTestStore(t, root)
	svc := &preClaimIntakeHookServiceStub{
		finalText: `{"classification":"atomic","confidence":0.99,"reasoning":"single-slice"}`,
