func danglingSuccessRecoveryReport(beadID string, recovery *DanglingSuccessRecovery) ExecuteBeadReport {
	report := ExecuteBeadReport{BeadID: beadID}
	if recovery == nil {
		report.Status = ExecuteBeadStatusExecutionFailed
		report.Detail = "dangling-success recovery returned no terminal outcome"
		report.OutcomeReason = "operator_required"
		return report
	}
	report.AttemptID = recovery.AttemptID
	report.SessionID = recovery.SessionID
	report.BaseRev = recovery.BaseRev
	report.ResultRev = recovery.ResultRev
	report.PreserveRef = recovery.PreserveRef

	switch recovery.Outcome {
	case danglingSuccessOutcomeClosed:
		report.Status = ExecuteBeadStatusAlreadySatisfied
		if recovery.AttemptID != "" && recovery.ResultRev != "" {
			report.Detail = fmt.Sprintf(
				"dangling-success recovery: already satisfied (attempt_id=%s result_rev=%s already merged)",
				recovery.AttemptID,
				recovery.ResultRev,
			)
		} else if recovery.ResultRev != "" {
			report.Detail = fmt.Sprintf(
				"dangling-success recovery: already satisfied (result_rev=%s already merged)",
				recovery.ResultRev,
			)
		} else {
			report.Detail = "dangling-success recovery: already satisfied (result_rev already merged)"
		}

		}, nil
	})

	out, err := executeCommand(
		factory.NewRootCommand(),
		"work",
		"--ignore-cooldown",
		"--reason", "operator unblock",
		"--no-review",
		"--no-review-i-know-what-im-doing",
	)
	require.NoError(t, err, "ddx work must drain cooled beads when override is explicit: %s", out)
	assert.Equal(t, []string{"cool-0", "cool-1", "cool-2", "cool-3", "cool-4"}, got)
}

// TestWork_NetworkFreeDrain_NoFetchInLoop verifies reliability principle P9:
// the drain loop's pre-claim hook never blocks on network I/O. The fixture
// repo has an origin remote whose URL points at a deleted path; the last
// observed refs/remotes/origin/main remains as a cached tip. A network-free
// drain must claim and execute a ready bead without error even though no
// `git fetch` against origin could succeed.
func TestWork_NetworkFreeDrain_NoFetchInLoop(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	gitEnv := gitpkg.CleanEnv()
	runGitEnv := func(dir string, args ...string) {
		t.Helper()
		c := exec.Command("git", args...)
		c.Dir = dir
		c.Env = gitEnv
		out, err := c.CombinedOutput()
		require.NoError(t, err, "git %v: %s", args, out)
	}

	originDir := t.TempDir()
	workDir := t.TempDir()
	runGitEnv(originDir, "init", "--bare", "-b", "main")
	runGitEnv(workDir, "clone", originDir, ".")
	runGitEnv(workDir, "config", "user.email", "test@ddx.test")
	runGitEnv(workDir, "config", "user.name", "DDx Test")
	require.NoError(t, os.WriteFile(filepath.Join(workDir, "seed.txt"), []byte("seed\n"), 0o644))
	runGitEnv(workDir, "add", "seed.txt")
	runGitEnv(workDir, "commit", "-m", "chore: initial seed")
	runGitEnv(workDir, "push", "-u", "origin", "main")

	// Break origin: point the remote URL at a deleted path and remove the bare
	// repo. refs/remotes/origin/main survives as the last-observed tip, so a
	// network-free ancestry check still resolves, but any fetch would fail.
	deletedOrigin := filepath.Join(t.TempDir(), "gone")
	runGitEnv(workDir, "remote", "set-url", "origin", "file://"+deletedOrigin)
	require.NoError(t, os.RemoveAll(originDir))

	seedExecuteBead(t, workDir, &bead.Bead{
		ID:        "ddx-network-free-drain",
		Title:     "network-free drain bead",
		Status:    bead.StatusOpen,
		Priority:  0,
		IssueType: bead.DefaultType,
	})

	var executed []string
	factory := NewCommandFactory(workDir)
	factory.AgentRunnerOverride = &tryHookRunnerStub{t: t}
	factory.tryExecutorOverride = agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		executed = append(executed, beadID)
		return agent.ExecuteBeadReport{
			BeadID:    beadID,
			Status:    agent.ExecuteBeadStatusSuccess,
			ResultRev: "rev-" + beadID,
		}, nil
	})

	out, err := executeCommand(
		factory.NewRootCommand(),
		"work",
		"--once",
		"--project", workDir,
		"--no-review",
		"--no-review-i-know-what-im-doing",
	)
	require.NoError(t, err, "network-free drain must claim and drain without origin reachability: %s", out)
	assert.Equal(t, []string{"ddx-network-free-drain"}, executed, "the ready bead must be claimed and executed")
}

type attemptBeadReaderFunc func(context.Context, string) (*bead.Bead, error)

func (f attemptBeadReaderFunc) Get(ctx context.Context, id string) (*bead.Bead, error) {
	return f(ctx, id)
}

func Test_WorkClaim_NotFoundRace(t *testing.T) {
	claimed := &bead.Bead{ID: "ddx-work-race-claim", Title: "Claimed bead"}

	var primaryCalls int
	primary := attemptBeadReaderFunc(func(ctx context.Context, id string) (*bead.Bead, error) {
		primaryCalls++
		return nil, fmt.Errorf("bead: not found: %s", id)
	})

	var refreshCalls int
	refreshed := attemptBeadReaderFunc(func(ctx context.Context, id string) (*bead.Bead, error) {
		refreshCalls++
		if id != claimed.ID {
			return nil, fmt.Errorf("bead: not found: %s", id)
		}
		return claimed, nil
	})

	got, err := resolveAttemptBead(context.Background(), claimed.ID, primary, func() attemptBeadReader {
		return refreshed
	}, nil)
	require.NoError(t, err)
	require.Same(t, claimed, got)
	assert.Equal(t, 1, primaryCalls, "primary lookup must miss once before refreshing")
	assert.Equal(t, 1, refreshCalls, "refresh lookup must retry exactly once")
}

type staleIndexAfterClaimStore struct {
	*bead.Store
	targetID      string
	claimed       int32
	postClaimGets int32
}

func (s *staleIndexAfterClaimStore) Claim(id, assignee string) error {
	if err := s.Store.Claim(id, assignee); err != nil {
		return err
	}
	if id == s.targetID {
		atomic.StoreInt32(&s.claimed, 1)
	}
	return nil
}

func (s *staleIndexAfterClaimStore) Get(ctx context.Context, id string) (*bead.Bead, error) {
	if id == s.targetID && atomic.LoadInt32(&s.claimed) == 1 {
		atomic.AddInt32(&s.postClaimGets, 1)
		return nil, fmt.Errorf("bead: not found: %s", id)
	}
	return s.Store.Get(ctx, id)
}

func TestWork_ClaimNotFoundRace_DoesNotFailUnderBeadUpdateChurn(t *testing.T) {
	baseStore := bead.NewStore(t.TempDir())
	require.NoError(t, baseStore.Init(context.Background()))

	targetID := "ddx-d3abb526"
	churnID := "ddx-work-race-churn"
	require.NoError(t, baseStore.Create(context.Background(), &bead.Bead{
		ID:       targetID,
		Title:    "Race target bead",
		Priority: 0,
	}))
	require.NoError(t, baseStore.Create(context.Background(), &bead.Bead{
		ID:       churnID,
		Title:    "Concurrent churn bead",
		Priority: 4,
	}))

	store := &staleIndexAfterClaimStore{
		Store:    baseStore,
		targetID: targetID,
	}
	require.NoError(t, store.Claim(targetID, "worker-a"))

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	var churnWG sync.WaitGroup
	churnWG.Add(1)
	go func() {
		defer churnWG.Done()
		ticker := time.NewTicker(10 * time.Millisecond)
		defer ticker.Stop()
		for {
			select {
			case <-ctx.Done():
				return
			case <-ticker.C:
				_ = baseStore.Update(context.Background(), churnID, func(b *bead.Bead) {
					if b.Notes == "" {
						b.Notes = "churn"
						return
					}
					b.Notes = b.Notes + "\nchurn"
				})
			}
		}
	}()

	got, err := resolveAttemptBead(context.Background(), targetID, store, func() attemptBeadReader {
		return bead.NewStoreWithCollection(baseStore.Dir, baseStore.Collection)
	}, nil)
	cancel()
	churnWG.Wait()

	require.NoError(t, err)
	require.NotNil(t, got)
	assert.Equal(t, targetID, got.ID)
	assert.NotZero(t, atomic.LoadInt32(&store.postClaimGets), "the stale primary lookup path must be exercised")

